        ///<summary>
        ///create ASA, set global key values
        ///</summary>
        /// <param name="assetPrice">ASA price in microAlgos </param>
        /// <param name="assetAmount">ASA inital amount in pieces </param>
        /// <param name="sellPeriodLength">sell period length in secs </param>
        /// <param name="assetValidityPeriod">asset validity in secs, after that time it can be clawbacked </param>
        public async Task Bootstrap(ulong assetPrice, ulong assetAmount, ulong sellPeriodLength, ulong assetValidityPeriod, Account _tx_sender, ulong? _tx_fee, string _tx_note = "", ulong _tx_roundValidity = 1000, List<BoxRef>? _tx_boxes = null, List<Transaction>? _tx_transactions = null, List<ulong>? _tx_assets = null, List<ulong>? _tx_apps = null, List<Address>? _tx_accounts = null, AVM.ClientGenerator.Core.OnCompleteType _tx_callType = AVM.ClientGenerator.Core.OnCompleteType.NoOp)
