            _tx_assets ??= new List<ulong>();
            _tx_apps ??= new List<ulong>();
            _tx_accounts ??= new List<Address>();
            byte[] abiHandle = { 66, 231, 55, 78 };
            var assetPriceAbi = new AVM.ClientGenerator.ABI.ARC4.Types.UInt64(); assetPriceAbi.From(assetPrice);
            var assetAmountAbi = new AVM.ClientGenerator.ABI.ARC4.Types.UInt64(); assetAmountAbi.From(assetAmount);
            var sellPeriodLengthAbi = new AVM.ClientGenerator.ABI.ARC4.Types.UInt64(); sellPeriodLengthAbi.From(sellPeriodLength);
            var assetValidityPeriodAbi = new AVM.ClientGenerator.ABI.ARC4.Types.UInt64(); assetValidityPeriodAbi.From(assetValidityPeriod);

